import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos } from '../services/productoService';
import { registrarVenta } from '../services/ventaService';

const Ventas = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [carrito, setCarrito] = useState({
        productoId: '',
        codigo: '',
        nombre: '',
        precio: 0, // Este ahora serĂˇ editable
        cantidad: 1,
        stockDisponible: 0
    });
    const [ventaRealizada, setVentaRealizada] = useState(null);

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            const fetchProds = async () => {
                const data = await obtenerProductos();
                setProductos(data);
            };
            fetchProds();
        }
    }, [navigate]);

    const seleccionarProducto = (e) => {
        const prodId = e.target.value;
        const prod = productos.find(p => p.id.toString() === prodId);
        
        if (prod) {
            setCarrito({
                productoId: prod.id,
                codigo: prod.codigo,
                nombre: prod.nombre,
                precio: prod.precioVenta, // Carga el precio base por defecto
                cantidad: 1,
                stockDisponible: prod.stock
            });
        }
    };

    const handleVenta = async (e) => {
        e.preventDefault();
        const matricula = localStorage.getItem('usuarioLogueado');

        if (carrito.cantidad > carrito.stockDisponible) {
            alert(`âťŚ Error: Solo quedan ${carrito.stockDisponible} unidades.`);
            return;
        }

        const datos = {
            codigoProducto: carrito.codigo,
            nombreProducto: carrito.nombre,
            cantidad: carrito.cantidad,
            precioVenta: carrito.precio, // EnvĂ­a el precio modificado al backend
            vendedorMatricula: matricula
        };

        const resultado = await registrarVenta(datos);
        if (resultado) {
            setVentaRealizada(resultado);
            alert("âś… Venta realizada con Ă©xito");
            setTimeout(() => {
                window.print();
                setCarrito({ productoId: '', codigo: '', nombre: '', precio: 0, cantidad: 1, stockDisponible: 0 });
            }, 500);
        }
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '800px', margin: '0 auto' }}>
            <div className="no-print">
                <h2 style={{ color: '#007bff', textAlign: 'center' }}>đź›’ Punto de Venta - Isla TecnolĂłgica</h2>
                
                <div style={{ background: '#f8f9fa', padding: '25px', borderRadius: '15px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
                    <form onSubmit={handleVenta}>
                        <div style={{ marginBottom: '15px' }}>
                            <label style={{ fontWeight: 'bold' }}>Producto:</label>
                            <select 
                                onChange={seleccionarProducto} 
                                style={{ width: '100%', padding: '12px', marginTop: '5px', borderRadius: '8px' }}
                                required
                            >
                                <option value="">-- Seleccionar --</option>
                                {productos.map(p => (
                                    <option key={p.id} value={p.id}>
                                        {p.nombre} ({p.codigo})
                                    </option>
                                ))}
                            </select>
                        </div>

                        {carrito.productoId && (
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px', marginBottom: '20px' }}>
                                <div>
                                    <label style={{ fontWeight: 'bold' }}>Cantidad:</label>
                                    <input 
                                        type="number" min="1" max={carrito.stockDisponible}
                                        value={carrito.cantidad} 
                                        onChange={(e) => setCarrito({...carrito, cantidad: parseInt(e.target.value)})}
                                        style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px' }}
                                    />
                                </div>
                                <div>
                                    {/* CAMPO DE PRECIO EDITABLE */}
                                    <label style={{ fontWeight: 'bold' }}>Precio Unitario ($):</label>
                                    <input 
                                        type="number" step="0.01"
                                        value={carrito.precio} 
                                        onChange={(e) => setCarrito({...carrito, precio: parseFloat(e.target.value)})}
                                        style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px', border: '2px solid #007bff' }}
                                    />
                                </div>
                                <div>
                                    <label style={{ fontWeight: 'bold' }}>Subtotal:</label>
                                    <div style={{ fontSize: '22px', fontWeight: 'bold', color: '#28a745', marginTop: '10px' }}>
                                        ${(carrito.precio * carrito.cantidad).toFixed(2)}
                                    </div>
                                </div>
                            </div>
                        )}

                        <button 
                            type="submit" 
                            disabled={!carrito.productoId}
                            style={{ width: '100%', padding: '15px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}
                        >
                            CONFIRMAR VENTA E IMPRIMIR
                        </button>
                    </form>
                </div>
            </div>

            {/* TICKET */}
            <div className="print-only" style={{ display: 'none', width: '80mm', textAlign: 'center', fontFamily: 'Courier New' }}>
                <h3>ISLA TECNOLĂ“GICA</h3>
                <p>--------------------------------</p>
                <p>VENTA: #{ventaRealizada?.id}</p>
                <p>FECHA: {new Date().toLocaleString()}</p>
                <p>--------------------------------</p>
                <div style={{ textAlign: 'left' }}>
                    <p>{ventaRealizada?.nombreProducto}</p>
                    <p>{ventaRealizada?.cantidad} x ${ventaRealizada?.precioVenta?.toFixed(2)}</p>
                    <p>TOTAL: ${ventaRealizada?.total?.toFixed(2)}</p>
                </div>
                <p>--------------------------------</p>
                <p>Atendido por: {ventaRealizada?.vendedorMatricula}</p>
            </div>
        </div>
    );
};

export default Ventas;
